require("LApp.gameplay.videobattle.const.LFightConst")
local LBattleBase = require("LApp.gameplay.videobattle.base.LBattleBase")
---@class LBattleMgr:LBattleBase
local LBattleMgr = classX("LBattleMgr", LBattleBase)

function LBattleMgr:Initialize()
    LBattleBase.Initialize(self)

    self._timeScale = 1

    ---@type LBattleViewMgr
    self._battleViewMgr = nil

    ---@type table<string,LBattleLogicMgr>
    self._battleMap = {}

    ---@type table<string, LFightReportGetter>
    self._reportGetters = {}

    ---@type table<number,LBattleProcess>
    self._battleProcessMap = {}

    ---@type LBattleDataMgr
    self._battleDataMgr = require("LApp.gameplay.videobattle.data.LBattleDataMgr"):new()
    self._battleDataMgr:Initialize()

    --self:AddEventHandler(EventNames.BATTLE_REPORT_START, self.OnBattleReportStart, self)
    --self:AddEventHandler(EventNames.LEVEL_LOAD_OK, self.OnLevelLoadOk, self)

    MgrCenter.GameMgr:RegisterTimeSchedule(self)
end

function LBattleMgr:Dispose()
    if self._battleMap then
        for k,v in pairs(self._battleMap) do
            v:Dispose()
        end
    end

    if self._reportGetters then
        for k,v in pairs(self._reportGetters) do
            v:Dispose()
        end
    end

    if self._battleViewMgr then
        self._battleViewMgr:Dispose()
    end

    if self._battleProcessMap then
        for k,v in pairs(self._battleProcessMap) do
            v:Dispose()
        end
    end

    if self._battleDataMgr then
        self._battleDataMgr:Dispose()
    end

    LBattleBase.Dispose(self)

    self._battleMap = {}
    self._reportGetters = {}
    self._battleProcessMap = {}

    self._battleViewMgr = nil

    self._battleDataMgr = nil
end


function LBattleMgr:OnScreenSizeChange()
    if self._battleViewMgr then
        self._battleViewMgr:OnScreenSizeChange()
    end
end

function LBattleMgr:OnNetReConnected()
    local battleProcessMap = self._battleProcessMap
    for k, v in pairs(battleProcessMap) do
        ---重发结算请求
        v:CheckResendReqResult()
        ---重发战斗请求
        v:CheckResendReqCombat()

    end
end

function LBattleMgr:OnLevelLoadOk(levelName)
    if levelName == LevelNames.Battle then
        if self._battleViewMgr then self._battleViewMgr:InitBattleView() end
    end
end

---@return LBattleDataMgr
function LBattleMgr:GetDataMgr()
    return self._battleDataMgr
end

---@param formation1 LxFormationObj
---@param formation2 LxFormationObj
function LBattleMgr:ShowEditor(formation1, formation2)
    self:InnerShowEditor(formation1, formation2)
end

function LBattleMgr:ReadyBattleView()
    if self._battleViewMgr then self._battleViewMgr:ReadyBattle() end
end

function LBattleMgr:SetCameraMode(mode)
    if self._battleViewMgr then self._battleViewMgr:SetCameraMode(mode) end
end

function LBattleMgr:SetFormationRoot(mode)
    if self._battleViewMgr then self._battleViewMgr:SetFormationRoot(mode) end
end

---@param formation1 LxFormationObj
---@param formation2 LxFormationObj
function LBattleMgr:ShowFormation(config, formation1, formation2)
    self:InnerShowFormation(config, formation1, formation2)
end

function LBattleMgr:ShowLiveBattle(battleType)
    ---@type LBattleLogicMgr
    local battle = self:GetLiveBattle(battleType)
    if battle then
        self:InnerShowBattle(battle, BattleStartType.LikeResumeLive)
        return true
    else
        return false
    end
end
--- 只有完整的战报才能跳过
function LBattleMgr:SkipBattle(reportId)
    local battle = self._battleMap[reportId]
    if not battle then
        return
    end
    battle:SkipBattle()
    if self:IsBattleShow(reportId) then
        self._battleViewMgr:ClearView()
    end
end

function LBattleMgr:ReqSkipBattle(reportId)
    local battle = self._battleMap[reportId]
    if not battle then
        return
    end
    battle:ReqSkipBattle()
end

function LBattleMgr:ResetBattle(reportId)
    local battle = self._battleMap[reportId]
    if not battle then
        return
    end
    battle:ResetBattle()
end

function LBattleMgr:ReplayBattle(reportId, bShowView)
    local battle = self._battleMap[reportId]
    if not battle then
        return
    end
    if bShowView then
        self:InnerShowBattle(battle, BattleStartType.LikeReplay, true)
    else
        battle:ReplayBattle()
    end
end

function LBattleMgr:AddBattle(reportId, reportData, bShowView, config)
    ---@type LBattleLogicMgr
    local battle = self._battleMap[reportId]
    if not battle or not battle:IsLive() then
        battle = require("LApp.gameplay.videobattle.logic.LBattleLogicMgr"):new(reportId, reportData)
        battle:SetDataMgr(self._battleDataMgr)
        battle:Initialize()
        battle:SetBattleConfig(config)
        self._battleMap[reportId] = battle
    end

    if bShowView then
        self:InnerShowBattle(battle, BattleStartType.LikeNewStart)
    else
        battle:SetAutoNext(true, true)
        battle:PlayBattle()
    end
end

function LBattleMgr:PauseBattle(reportId, bPause, bOnlyLogic)
    ---@type LBattleLogicMgr
    local battle = self._battleMap[reportId]
    if battle then
        if bPause then
            battle:PauseBattle()
        else
            battle:ResumeBattle()
        end
    end

    if not bOnlyLogic and self:IsBattleShow(reportId) then

        self._battleViewMgr:PauseBattle(bPause)

        if bPause then
            MgrCenter.GameMgr:PauseTime()
        else
            MgrCenter.GameMgr:ResumeTime()
            self:SetTimeScale( self._timeScale)
        end
    end
end

function LBattleMgr:SetTimeScale(timeScale)
    if  MgrCenter.GameMgr:IsPauseTime() then
        return false
    end
    self._timeScale = timeScale
    MgrCenter.GameMgr:SetTimeScale(timeScale)
    MgrCenter.GameMgr:ResumeTime()
    return true
end

function LBattleMgr:GetSkillViewUnitList(casterId, worldPos, skillRefId)
    if self._battleViewMgr then
        return self._battleViewMgr:GetSkillUnitList(casterId, worldPos, skillRefId)
    end
    return {}
end
---@return LBattleLogicUnit
function LBattleMgr:GetBattleUnitData(reportId, unitId)
    if not reportId or not unitId then
        return nil
    end
    ---@type LBattleLogicMgr
    local battle = self._battleMap[reportId]
    if battle then
        return battle:GetUnitData(unitId)
    else
        return nil
    end
end

function LBattleMgr:AddOps(reportId, targetType, targetId, skillRefId, effectIds)
    ---@type LBattleLogicMgr
    local battle = self._battleMap[reportId]
    if battle then
        battle:AddOps(targetType, targetId, skillRefId, effectIds)
    end
end

function LBattleMgr:SetBattleAutoNext(reportId, bAutoNext, bRunStep)
    ---@type LBattleLogicMgr
    local battle = self._battleMap[reportId]
    if battle then
        battle:SetAutoNext(bAutoNext, bRunStep)
        if battle:IsBattleEndFinished() then
            self:RemoveBattle(reportId, battle:GetBattleType())
        end
    end
end

function LBattleMgr:OnBattleOps(reportId)
    ---@type LBattleLogicMgr
    local battle = self._battleMap[reportId]
    if not battle or not battle:IsLive() then
        return
    end
    battle:OnBattleOps()
end

---是否可以在前台下一关
function LBattleMgr:IsShowBattleNextInFront(battleType)
    if not self._battleViewMgr then
        return true
    end
    if self._battleViewMgr then
        if self._battleViewMgr:GetBattleType() == battleType then
            return true
        end
        return false
    end
end

function LBattleMgr:IsBattleShow(reportId, bCheckLoad)
    if self._battleViewMgr and self._battleViewMgr:GetReportId() == reportId then
        return self._battleViewMgr:IsLoaded() or not bCheckLoad
    end
    return false
end

function LBattleMgr:IsAnyBattleShow()
    if self._battleViewMgr then
        return MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle) and self._battleViewMgr:IsBattleMode()
    end
    return false
end

function LBattleMgr:IsBattleInBackground(battleType)
    local process = self._battleProcessMap[battleType]
    if process and process:IsLive() and process:IsBattleInBackground() then
        return true
    end
    return false
end

function LBattleMgr:HasAnyLiveBattle()
    for i, battle in pairs(self._battleMap) do
        if battle:IsLive() then
            return true
        end
    end
    return false
end

function LBattleMgr:GetBattleLogic(reportId)
    reportId = reportId or ""
    local battle = self._battleMap[reportId]
    return battle
end

function LBattleMgr:HasBattleReport(reportId)
    local battle = self._battleMap[reportId]
    return (battle and battle:IsLive())
end

function LBattleMgr:HasLiveBattleType(battleType)
    local battle = self:GetLiveBattle(battleType)
    return (battle ~= nil)
end

function LBattleMgr:GetBattleConfig(battleType)
    local battle = self:GetLiveBattle(battleType)
    return battle and battle:GetBattleConfig()
end

function LBattleMgr:GetLiveBattle(battleType)
    for i, battle in pairs(self._battleMap) do
        if battle:GetBattleType() == battleType and battle:IsLive() then
            return battle
        end
    end
    return nil
end

function LBattleMgr:GetBattleList()
    local battleList = {}
    if self._battleMap then
        for k,battle in pairs(self._battleMap) do
            if battle:IsLive() then
                table.insert(battleList, battle)
            end
        end
    end
    return battleList
end

---@param reportId string
function LBattleMgr:RemoveBattle(reportId, battleType, ignoreDisposeReport)
    local battle = self._battleMap[reportId]
    if not battle and battleType then
        for i, v in pairs(self._battleMap) do
            if v:GetBattleType() == battleType then
                battle = v
                break
            end
        end
    end
    local reportData = battle:GetReportData()
    self:RemoveBattleProcess(reportData.attachProcess)
    ModuleCenter.Battle:RemoveBattleReport(reportId, ignoreDisposeReport)
    local bCloseView = false
    if battle then
        battle:Dispose()
        self._battleMap[reportId] = nil
    end
    if self:IsBattleShow(reportId) then
        bCloseView = true
        self:RemoveBattleView()
    end

    return bCloseView
end

function LBattleMgr:ChangeShowBattleToBackground()
    local viewMgr = self._battleViewMgr
    if viewMgr then
        local battleType = viewMgr:GetBattleType()
        local battleProcess = self:GetBattleProcess(battleType)
        if battleProcess and not battleProcess:IsDisposed() then
            battleProcess.battleConfig.isOpenWithoutView = true
        end
    end

end

function LBattleMgr:RemoveBattleView(reportId)
    local bCloseView = false

    ---@type LBattleViewMgr
    local viewMgr = self._battleViewMgr
    if viewMgr then
        -- 退出战斗显示，就开启主动下一步
        if not reportId then
            reportId = viewMgr:GetReportId()
        end
        if reportId == viewMgr:GetReportId() then
            viewMgr:Dispose()
            self._battleViewMgr = nil
            bCloseView = true
            self:SetBattleAutoNext(reportId, true, true)
        end
    end
    self:SetTimeScale(1)

    return bCloseView
end

function LBattleMgr:GetBattleProcess(battleType)
    return self._battleProcessMap[battleType]
end

---@param battleProcess LBattleProcess
function LBattleMgr:RemoveBattleProcess(battleProcess)
    if not battleProcess then return end
    for k,v in pairs(self._battleProcessMap) do
        if v == battleProcess then
            self._battleProcessMap[k] = nil
            break
        end
    end
    battleProcess:Dispose()
end

function LBattleMgr:AddBattleProcess(battleType)
    local process = require("LApp.gameplay.videobattle.data.LBattleProcess"):new(battleType)
    local oldProcess = self._battleProcessMap[battleType]
    self._battleProcessMap[battleType] = process
    if oldProcess then
        oldProcess:Dispose()
    end
    return process
end

--- 呈现编辑器
---@param formation1 LxFormationObj
---@param formation2 LxFormationObj
function LBattleMgr:InnerShowEditor(formation1, formation2)
    if not self._battleViewMgr then
        self._battleViewMgr = require("LApp.gameplay.videobattle.view.LBattleViewMgr"):new()
        self._battleViewMgr:SetDataMgr(self._battleDataMgr)
        self._battleViewMgr:Initialize()
    end
    self._battleViewMgr:InitBattleView()
    self._battleViewMgr:ShowEditor(formation1, formation2)
end


--- 呈现布阵
---@param formation1 LxFormationObj
