function LBattleMgr:InnerShowFormation(config, formation1, formation2)
    if not self._battleViewMgr then
        self._battleViewMgr = require("LApp.gameplay.videobattle.view.LBattleViewMgr"):new()
        self._battleViewMgr:SetDataMgr(self._battleDataMgr)
        self._battleViewMgr:Initialize()
    end
    self._battleViewMgr:InitBattleView()
    self._battleViewMgr:ShowFormation(config, formation1, formation2)
end

--- 呈现战斗
---@param battle LBattleLogicMgr
function LBattleMgr:InnerShowBattle(battle, startType, replay)
    if not battle then return end
    if not self._battleViewMgr then
        self._battleViewMgr = require("LApp.gameplay.videobattle.view.LBattleViewMgr"):new()
        self._battleViewMgr:SetDataMgr(self._battleDataMgr)
        self._battleViewMgr:Initialize()
    end
    if self._battleViewMgr and (self._battleViewMgr:GetReportId() ~= battle:GetReportId() or replay) then
        self._battleViewMgr:InitBattleView()
        self._battleViewMgr:ShowBattle(battle, startType)
    end
end

function LBattleMgr:GetBattleView()
    return self._battleViewMgr
end

---从资源加载战报
function LBattleMgr:AddTextAssetReportGetter(assetName,callback, reportData)
    local key = assetName
    local getter = self._reportGetters[key]
    if getter and not getter:IsDisposed() then
        if getter:IsReady() then
            getter:AddCallback(callback, reportData)
            getter:ExecuteCallback()
            return
        elseif not getter:IsError() then
            getter:AddCallback(callback, reportData)
            return
        end
        getter:Dispose()
    end
    getter = require("LApp.gameplay.videobattle.logic.LFightReportGetter"):new()
    getter:SetAssetInfo(assetName)
    getter:AddCallback(callback, reportData)
    self._reportGetters[key] = getter
end

function LBattleMgr:AddReportGetter(serverId, reportId, callback, reportData)
    local key = serverId.."/"..reportId
    local getter = self._reportGetters[key]
    if getter and not getter:IsDisposed() then
        if getter:IsReady() then
            getter:AddCallback(callback, reportData)
            getter:ExecuteCallback()
            return
        elseif not getter:IsError() then
            getter:AddCallback(callback, reportData)
            return
        end
        getter:Dispose()
    end
    getter = require("LApp.gameplay.videobattle.logic.LFightReportGetter"):new()
    getter:SetReportInfo(reportId, serverId)
    getter:AddCallback(callback, reportData)
    self._reportGetters[key] = getter
end

function LBattleMgr:OnUpdate()
    if self._isDisposed  then return end
    local getters = self._reportGetters
    for k,v in pairs(getters) do
        if v:IsEnd() then
            getters[k] = nil
            v:Dispose()
        end
        v:OnUpdate()
    end

    local time = Time.time
    local deltaTime = Time.deltaTime
    local battleMap = self._battleMap
    if battleMap ~= nil then
        for k,v in pairs(battleMap) do
            v:OnUpdate(time, deltaTime)
        end
    end
    if self._battleViewMgr then
        self._battleViewMgr:OnUpdate(time, deltaTime)
    end
end

function LBattleMgr:GetTimeScale()
    return self._timeScale
end

return LBattleMgr